const sharp = require\('sharp'\);
const fs = require\('fs'\);
const path = require\('path'\);

const images = ['before-after-1.jpg', 'before-after-2.jpg', 'our-junk-removal-team.jpg', 'founder.jpg'];
const pubDir = 'public';

\(async \(\) => {
  for \(const img of images\) {
    const src = path.join\(pubDir, img\);
    if \(!fs.existsSync\(src\)\) { console.log\(img + ': NOT FOUND'\); continue; }
    const before = fs.statSync\(src\).size;
    const tmp = path.join\(pubDir, img + '.tmp'\);
    const info = await sharp\(src\).resize\(1200, null, { withoutEnlargement: true }\).jpeg\({ quality: 80 }\).toFile\(tmp\);
    fs.renameSync\(tmp, src\);
    console.log\(img + ': ' + Math.round\(before/1024\) + 'KB -> ' + Math.round\(info.size/1024\) + 'KB'\);
  }
}\)\(\);
